import './ButtonGroup.scss';

import { Button } from ':components/Button/Button';
import type { ButtonProps } from ':components/Button/Button.types';
import React, { useEffect } from 'react';

import type { ButtonGroupProps } from './ButtonGroup.types';

const DEPRECATION_MESSAGE =
	'[ButtonGroup] Компонент устарел и будет удалён в будущих версиях. Используйте SegmentControl.';

/**
 * @deprecated **УСТАРЕВШИЙ КОМПОНЕНТ!** Используйте вместо него компонент SegmentControl
 */
export const ButtonGroup: React.FC<ButtonGroupProps> = ({
	selectedOption,
	onChange,
	options,
	className = '',
	activeClassName = 'active',
	disabledAll = false,
	size = 'medium',
	fullWidth = false,
	type = 'primary',
	alwaysSelected = false,
	customButtonWidth,
	dataTestId = 'ButtonGroup',
}) => {
	const handleChange = (option): void => {
		const isSelected = option.id === selectedOption?.id;
		if (isSelected) return;
		onChange(option);
	};

	useEffect(() => {
		console.warn(DEPRECATION_MESSAGE);
	}, []);

	const activeButtonClassType = type === 'primary' ? 'primary' : 'secondary';

	return (
		<div className={['dsb_button-group', activeButtonClassType, className].join(' ')} data-testid={dataTestId}>
			{options?.map(option => {
				const isSelected = option.id === selectedOption?.id;
				const isDisabled = disabledAll || option.disabled;

				const { wrapper: _wrapper, ...optionForButton } = option;
				const btnProps: ButtonProps = isSelected
					? { ...optionForButton, variant: 'contained', className: activeClassName }
					: { ...optionForButton, variant: 'outlined' };

				const ButtonComponent = (
					<Button
						style={customButtonWidth && { width: `${customButtonWidth}px` }}
						{...btnProps}
						key={option.id}
						size={size}
						fullWidth={fullWidth || option.fullWidth}
						disabled={isDisabled}
						tabIndex={isDisabled ? -1 : undefined}
						onClick={(): void => handleChange(option)}
					>
						{option.label}
					</Button>
				);

				if (_wrapper) {
					const WrapperComponent = _wrapper;
					return <WrapperComponent key={option.id}>{ButtonComponent}</WrapperComponent>;
				}

				return ButtonComponent;
			})}
		</div>
	);
};
